TraceEnricher.java<pre><code>@Component
public class TraceEnricher&lt;T&gt; implements PayloadEnricher&lt;T&gt; {

    private final Tracer tracer;

    @Override
    public ReferentialPayload&lt;T&gt; enrichOnStore(
            Failover failover, Class&lt;T&gt; clazz, ReferentialPayload&lt;T&gt; payload) {
        // inject current trace ID into metadata
        if (payload.getPayload() instanceof Referential r) {
            r.getMetadata().add("traceId", tracer.currentSpan().context().traceId());
        }
        return payload;
    }

    @Override
    public ReferentialPayload&lt;T&gt; enrichOnRecover(
            Failover failover, Class&lt;T&gt; clazz,
            @Nullable ReferentialPayload&lt;T&gt; payload, Throwable cause) {
        if (payload != null &amp;&amp; payload.getPayload() instanceof Referential r) {
            r.setUpToDate(false);
            r.setAsOf(payload.getAsOf());
        }
        return payload;
    }
}
</code></pre>

FixedDatabaseResolver.java<pre><code>@Component
public class FixedDatabaseResolver implements DatabaseResolver {

    @Value("${failover.database-product:}")
    private String product;

    @Override
    public String resolve(DataSource dataSource) {
        if (!product.isBlank()) return product;
        try (Connection c = dataSource.getConnection()) {
            return c.getMetaData().getDatabaseProductName();
        } catch (SQLException e) {
            throw new FailoverStoreException("Cannot resolve database product", e);
        }
    }
}
</code></pre>

LogAndNeverThrowPolicy.java<pre><code>@Component
public class LogAndNeverThrowPolicy implements MethodExceptionPolicy {

    @Override
    public void handle(MethodExceptionContext context) {
        log.warn("Failover: no recovery for '{}', suppressing exception",
                 context.getFailover().name(), context.getCause());
        // returning without throwing means the caller gets null
    }
}
</code></pre> application.yml<pre><code>failover:
  exception-policy: custom
</code></pre> <p><code>MethodExceptionContext</code> carries:</p> <ul> <li><code>getFailover()</code> — the <code>@Failover</code> annotation metadata</li> <li><code>getArgs()</code> — the original method arguments</li> <li><code>getCause()</code> — the upstream exception</li> <li><code>getClazz()</code> — the return type class</li> </ul>

SchemaQualifiedQueryResolver.java<pre><code>@Component
public class SchemaQualifiedQueryResolver&lt;T&gt; implements FailoverStoreQueryResolver&lt;T&gt; {

    private final String schema;

    public SchemaQualifiedQueryResolver(@Value("${db.schema:PUBLIC}") String schema) {
        this.schema = schema;
    }

    @Override
    public String storeQuery(String tableName) {
        return "MERGE INTO " + schema + "." + tableName +
               " (FAILOVER_NAME, FAILOVER_KEY, AS_OF, EXPIRE_ON, PAYLOAD, PAYLOAD_CLASS)" +
               " KEY (FAILOVER_NAME, FAILOVER_KEY)" +
               " VALUES (?, ?, ?, ?, ?, ?)";
    }

    @Override
    public String findQuery(String tableName) {
        return "SELECT * FROM " + schema + "." + tableName +
               " WHERE FAILOVER_NAME = ? AND FAILOVER_KEY = ?";
    }

    @Override
    public String deleteQuery(String tableName) {
        return "DELETE FROM " + schema + "." + tableName +
               " WHERE FAILOVER_NAME = ? AND FAILOVER_KEY = ?";
    }

    @Override
    public String cleanByExpiryQuery(String tableName) {
        return "DELETE FROM " + schema + "." + tableName +
               " WHERE EXPIRE_ON &lt; ?";
    }

    @Override
    public RowMapper&lt;ReferentialPayload&lt;T&gt;&gt; rowMapper() {
        return null;   // null = use default row mapper
    }
}
</code></pre>

